query:
ALTER TABLE employees ADD COLUMN is_verified BOOLEAN NOT NULL DEFAULT FALSE;
-- Mark all existing admin-created employees (those with non-TEMP employee numbers) as verified
UPDATE employees SET is_verified = TRUE WHERE employee_number NOT LIKE 'TEMP-%';

